            AppRoutes = """["/admin/events"]""",
            Tags = """["events","admin","reference"]""",
            ContentJson = """{"title":"Events Field Reference","groups":[{"heading":"Event Form Fields","items":[{"label":"Title","value":"The event's name — what people see in the list and in their invite. Make it specific so it's clear at a glance, like 'Weekly Safety Briefing', 'Q2 Project Review', or 'New Hire Orientation'."},{"label":"Event Type","value":"Choose Meeting, Training, Safety, or Other. This sets the icon in the list and lets you filter to one kind. New events start as Meeting, so switch it if you're scheduling a training or safety event."},{"label":"Location","value":"Where it happens, in person or online — 'Conference Room B', 'Shop Floor Bay 3', or a video-call link. Optional, but worth filling in so nobody has to ask where to go."},{"label":"Start Date","value":"The day the event begins. Pair it with the start time to set exactly when it kicks off."},{"label":"Start Time","value":"The time it begins. New events default to 9:00 in the morning; adjust to the real start."},{"label":"End Date","value":"The day it ends. For a one-day event, keep the same date as the start."},{"label":"End Time","value":"When it wraps up. The end has to come after the start, so a short meeting might run 9:00 to 9:30."},{"label":"Description","value":"The agenda, what to bring, or a video-call link. Optional, but it's the place to put anything people need to prepare."},{"label":"Attendees","value":"Pick who should come from your active employees, listed by name. Add as many as you need — everyone you pick gets an invite when you save."},{"label":"Required Attendance","value":"Flip this on when showing up isn't optional. It makes the invite stand out and puts a yellow Required label in the list. Use it for safety briefings and mandatory training; leave it off for anything people can skip."}]},{"heading":"Who's Coming","items":[{"label":"The person","value":"Each attendee is one of your employees, listed by name so you know exactly who's expected."},{"label":"Their status","value":"Where each person stands: Invited, Accepted, Declined, or Attended. It's how you read turnout — who's confirmed, who's out, and who actually showed."},{"label":"Headcount","value":"The list shows how many people are invited to each event, so you can gauge turnout at a glance before you walk in."}]},{"heading":"Event Types","items":[{"label":"Meeting","value":"Team meetings, project reviews, stand-ups, one-on-ones, and other working sessions."},{"label":"Training","value":"Skills training, onboarding, certification prep, and other learning sessions."},{"label":"Safety","value":"Safety briefings, emergency drills, compliance reviews, and hazard training."},{"label":"Other","value":"Company socials, announcements, facility tours, and anything the other types don't cover."}]},{"heading":"Attendee Statuses","items":[{"label":"Invited","value":"They're on the list but haven't answered yet — the starting point for everyone you add."},{"label":"Accepted","value":"They've confirmed they'll be there."},{"label":"Declined","value":"They can't make it — a heads-up to follow up if it's someone you need."},{"label":"Attended","value":"They showed up. This is your record for compliance — proof of who was at a safety training when an auditor or customer asks."}]},{"heading":"Buttons and Actions","items":[{"label":"New Event","value":"Starts a fresh event, ready to fill in — set the type, time, attendees, and whether it's required, then save."},{"label":"Save","value":"Creates the event and sends invites to everyone on it. If something required is still blank, Save stays disabled until you fill it in; the marker beside it tells you what's missing."},{"label":"Cancel (in the form)","value":"Closes the form and drops your changes — nothing is saved and no invites go out."},{"label":"Edit","value":"The pencil on a row reopens the event with its current details, including who's invited, so you can add people or shift the time."},{"label":"Cancel Event","value":"The red X on a row calls the event off. You'll confirm first, then everyone invited is told it's cancelled. The event leaves the calendar but stays in your history."},{"label":"Type Filter","value":"The menu above the list narrows it to one kind of event. Choose Safety to review just your safety schedule, Training for training, and so on."}]},{"heading":"Getting Turnout Right","items":[{"label":"Reserve Required for real must-attends","value":"A Required event stands out in notifications and carries a yellow label. Save it for things people truly can't skip, so the label keeps its weight."},{"label":"Invite the whole crew for briefings","value":"When a safety talk is for the entire floor, add everyone. Attended then becomes a clean roster of who really made it."},{"label":"Put the details in the description","value":"Agenda, what to bring, or the video-call link — anything in the description saves you a round of questions beforehand."},{"label":"Let the reminder do the chasing","value":"Everyone invited gets an automatic nudge before the event, so you don't have to round people up the morning of."},{"label":"Give an accurate end time","value":"The end has to come after the start. A realistic window helps people plan the rest of their day around it."},{"label":"Recurring events","value":"There's no repeat option yet, so create each occurrence as its own event. Keep the title consistent so they're easy to find."},{"label":"Follow up on a declined training","value":"If someone can't make a required training, schedule a make-up event and mark their attendance there once they've caught up."},{"label":"Plans changed","value":"Edit to shift the time or swap attendees, or cancel if it's off — either way everyone invited stays in the loop."},{"label":"Keep an eye on the count","value":"A low headcount on a mandatory event is your cue to nudge people before the day arrives."},{"label":"Filter to prep for the week","value":"Use the type filter to pull up just your safety or training events and confirm everything's scheduled and staffed."}]},{"heading":"List Columns","items":[{"label":"Title","value":"The event name. Click to sort the list alphabetically."},{"label":"Type","value":"The event's kind, shown with its icon. Sort or filter by it."},{"label":"Start","value":"When the event begins. Click to sort chronologically and see what's coming up next."},{"label":"End","value":"When the event ends. Click to sort."},{"label":"Location","value":"Where it happens, in person or online."},{"label":"Attendees","value":"The headcount — how many people you've invited."},{"label":"Required","value":"A yellow Required tag on mandatory events, plain Optional otherwise. Sort by it to pull must-attends to the top."},{"label":"Actions","value":"The edit (pencil) and cancel (X) buttons on each row."}]},{"heading":"What People Get","items":[{"label":"Invitation","value":"Everyone you invite gets a notification the moment you save — who invited them, the event, and when it starts. Required events land with more emphasis."},{"label":"Reminder","value":"A nudge before the event starts, so people show up on time even if the invite slipped their mind."},{"label":"Cancellation","value":"If you call the event off, everyone invited is told it's cancelled, so nobody shows up to an empty room."}]}]}"""
        });

