        await GetOrCreateModule(new TrainingModule
        {
            Title = "Events Knowledge Check",
            Slug = "events-quiz",
            Summary = "Test your knowledge of Events: types, attendees, attendance statuses, reminders, and everyday scheduling tasks.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/admin/events"]""",
            Tags = """["events","admin","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ev1","text":"You need to schedule a mandatory safety briefing for all shop floor workers next Tuesday. Where do you create this event?","options":[{"id":"a","text":"Dashboard > Calendar widget > click the date"},{"id":"b","text":"Admin > Events > click New Event, choose the Safety type, turn on Required Attendance","isCorrect":true},{"id":"c","text":"Time Tracking > create a new time entry with category 'Safety'"},{"id":"d","text":"Shop Floor Display > Upcoming section > Add Event"}],"explanation":"Events are created in Admin > Events. Click New Event, choose the Safety type, fill in the details, pick your attendees, and turn on Required Attendance. A yellow Required label appears in the list, and attendees get an invitation that stands out more strongly."},{"id":"ev2","text":"What are the four event types available in the system?","options":[{"id":"a","text":"Urgent, Standard, Optional, Recurring"},{"id":"b","text":"Meeting, Training, Safety, Other","isCorrect":true},{"id":"c","text":"Internal, External, Virtual, Hybrid"},{"id":"d","text":"Daily, Weekly, Monthly, Annual"}],"explanation":"The four event types are Meeting, Training, Safety, and Other. Each type has its own icon in the events list, so you can tell them apart at a glance."},{"id":"ev3","text":"An employee has been invited to an event but hasn't responded yet. What is their attendee status?","options":[{"id":"a","text":"Pending"},{"id":"b","text":"No Response"},{"id":"c","text":"Invited","isCorrect":true},{"id":"d","text":"Unconfirmed"}],"explanation":"The default status for a newly added attendee is Invited. It remains Invited until the employee responds. The four possible statuses are: Invited, Accepted, Declined, and Attended."},{"id":"ev4","text":"Among the four attendee statuses, which one tells you a person actually showed up — the status that matters when you need to prove attendance for compliance?","options":[{"id":"a","text":"Accepted — they confirmed beforehand"},{"id":"b","text":"Attended — the person was there","isCorrect":true},{"id":"c","text":"Completed — marks the training as done"},{"id":"d","text":"Present — a checked-in status"}],"explanation":"Attended is the status that says a person actually showed up. That's what compliance needs — proof of who was in the room, not just who said they'd come. The four statuses are Invited, Accepted, Declined, and Attended."},{"id":"ev5","text":"How does the system help make sure invited people show up?","options":[{"id":"a","text":"It calls each attendee's phone the morning of the event"},{"id":"b","text":"It posts the event to a public bulletin board only"},{"id":"c","text":"It sends each invited person an automatic reminder shortly before the event starts","isCorrect":true},{"id":"d","text":"There are no reminders — attendees must check the calendar themselves"}],"explanation":"Everyone invited gets an automatic reminder shortly before the event starts, so people show up on time even if the original invite slipped their mind. You don't have to chase anyone down."},{"id":"ev6","text":"You want to cancel a scheduled event. What happens when you click the cancel (X) icon on an event row?","options":[{"id":"a","text":"The event is erased for good, with no record left behind"},{"id":"b","text":"A confirmation window appears, and confirming cancels the event — it drops off the calendar but stays in your history","isCorrect":true},{"id":"c","text":"The event is moved to an archive section at the bottom of the page"},{"id":"d","text":"All attendees are removed but the event stays visible in the list"}],"explanation":"Cancelling doesn't erase an event. A window asks you to confirm and warns that attendees will be told. Once you confirm, the event drops off the calendar, but it stays in your history so you keep an accurate record of what was scheduled."},{"id":"ev7","text":"What's the difference between a Required and an Optional event?","options":[{"id":"a","text":"Required events block the attendee's calendar; optional events don't"},{"id":"b","text":"Required events show a yellow Required label in the list, and their invitation stands out more strongly in each person's notifications","isCorrect":true},{"id":"c","text":"Required events can only be created by admins; optional events can be created by anyone"},{"id":"d","text":"There is no functional difference — it's just a label"}],"explanation":"When you mark an event Required, two things change: its invitation stands out more strongly in each person's notifications, and a yellow Required label appears next to the event in the list."},{"id":"ev8","text":"You're looking at the events table and want to see only Training events. How do you filter?","options":[{"id":"a","text":"Click the Training column header to sort by type"},{"id":"b","text":"Use the Type filter menu above the list and select Training","isCorrect":true},{"id":"c","text":"Type 'Training' in the search box"},{"id":"d","text":"Right-click the list and select Filter > Training"}],"explanation":"The Type filter menu above the events list lets you show only one kind of event. Pick Training to see just training events, and the list updates right away."},{"id":"ev9","text":"You're creating an event and Save won't let you click it. How do you find out what's stopping you?","options":[{"id":"a","text":"Refresh the page and start the event over"},{"id":"b","text":"Guess which field is wrong and try each one"},{"id":"c","text":"Check the marker beside Save — it lists exactly what still needs filling in, like a missing title or start date","isCorrect":true},{"id":"d","text":"Nothing you can do — save anyway and fix it later"}],"explanation":"Save stays disabled until the event has everything it needs. The marker beside it spells out what's still missing — a title, a start date, and so on — so you know exactly what to fill in before it'll save."},{"id":"ev10","text":"Where else in the application do events appear besides the Admin > Events page?","options":[{"id":"a","text":"Only on Admin > Events — events are an admin-only feature"},{"id":"b","text":"On the Shop Floor Display's upcoming section and in each employee's Events tab in their profile","isCorrect":true},{"id":"c","text":"On the Dashboard calendar widget and the Kanban board sidebar"},{"id":"d","text":"In the Chat module as automated event announcements"}],"explanation":"Events appear in three places: Admin > Events (main management view), the Shop Floor Display (upcoming events section so production workers see what's scheduled), and the Employee Detail view (Events tab showing events each person is invited to or has attended)."},{"id":"ev11","text":"A customer audit asks you to prove which employees attended last quarter's safety training. Where do you look?","options":[{"id":"a","text":"The Time Tracking module, filtered to the training day"},{"id":"b","text":"Open the employee's profile Events tab, or the training event's attendee list, and check who's marked Attended","isCorrect":true},{"id":"c","text":"The Shop Floor Display, which keeps a permanent attendance log"},{"id":"d","text":"Nowhere — attendance isn't recorded once an event is over"}],"explanation":"Each person's profile has an Events tab listing the events they were invited to and whether they attended, and the event itself carries an attendee list. The Attended status on those is your compliance record of who was actually there."}]}"""
